import React, { useEffect, useRef, useState } from 'react';
import API from '../../api/axios';
import MessageBubble from './MessageBubble';
import TypingIndicator from './TypingIndicator';

export default function ChatBox({ chat, socketRef }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [selectedFile, setSelectedFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [fileLoading, setFileLoading] = useState(false);

  const [incomingCall, setIncomingCall] = useState(null);
  const [callActive, setCallActive] = useState(false);

  const localVideo = useRef(null);
  const remoteVideo = useRef(null);
  const peerRef = useRef(null);
  const localStreamRef = useRef(null);

  const typingTimeout = useRef(null);
  const scrollRef = useRef();

  // helper to get current user and partner id for one-to-one chat
  const getMe = () => JSON.parse(localStorage.getItem('user') || 'null');
  const getPartnerId = () => {
    const me = getMe();
    if (!chat) return null;
    // if chat.users is array of user objects or ids
    if (Array.isArray(chat.users)) {
      const partner = chat.users.find(u => {
        const id = typeof u === 'string' ? u : (u._id || u.id);
        return String(id) !== String(me?._id);
      });
      if (!partner) return null;
      return typeof partner === 'string' ? partner : (partner._id || partner.id);
    }
    // fallback: if chat itself is a user object
    return chat._id || chat.id || null;
  };

  const loadMessages = async () => {
    if (!chat) return;
    try {
      const res = await API.get(`/messages/${chat._id}`);
      setMessages(res.data);
      scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
    } catch (err) { console.error(err); }
  };

  useEffect(() => {
    loadMessages();
    const socket = socketRef?.current;
    if (socket && chat) {
      socket.emit('join_chat', chat._id);
    }
    // mark seen when opening chat
    (async () => {
      if (!chat) return;
      try {
        await API.put('/messages/seen', { chatId: chat._id });
      } catch (e) {}
    })();
  }, [chat]);

  // socket listeners for messages & typing
  useEffect(() => {
    const socket = socketRef?.current;
    if (!socket) return;

    const handleMessage = (msg) => {
      const chatId = msg.chat?._id || msg.chat;
      if (String(chatId) === String(chat?._id)) {
        setMessages((prev) => [...prev, msg]);
        scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
      }
    };
    const handleTyping = () => setIsTyping(true);
    const handleStopTyping = () => setIsTyping(false);

    socket.on('message_received', handleMessage);
    socket.on('typing', handleTyping);
    socket.on('stop_typing', handleStopTyping);

    return () => {
      socket.off('message_received', handleMessage);
      socket.off('typing', handleTyping);
      socket.off('stop_typing', handleStopTyping);
    };
  }, [chat?._id, socketRef]);

  // --- WebRTC signaling listeners ---
  useEffect(() => {
    const socket = socketRef?.current;
    if (!socket) return;

    const onIncomingCall = ({ offer, from }) => {
      setIncomingCall({ offer, from });
    };

    const onCallAnswered = async ({ answer }) => {
      try {
        if (peerRef.current && answer) {
          await peerRef.current.setRemoteDescription(answer);
          setCallActive(true);
        }
      } catch (err) {
        console.error('Error setting remote desc (answer):', err);
      }
    };

    const onIceCandidate = async ({ candidate }) => {
      try {
        if (peerRef.current && candidate) {
          await peerRef.current.addIceCandidate(new RTCIceCandidate(candidate));
        }
      } catch (err) {
        console.error('Error adding ICE candidate:', err);
      }
    };

    socket.on('incoming_call', onIncomingCall);
    socket.on('call_answered', onCallAnswered);
    socket.on('ice_candidate', onIceCandidate);

    return () => {
      socket.off('incoming_call', onIncomingCall);
      socket.off('call_answered', onCallAnswered);
      socket.off('ice_candidate', onIceCandidate);
    };
  }, [socketRef]);

  // --- call helpers ---
  const createPeer = (targetId) => {

    const pc = new RTCPeerConnection({
      iceServers: [
        { urls: "stun:stun.l.google.com:19302" },
        { urls: "stun:stun1.l.google.com:19302" }
      ]
    });

    pc.ontrack = (event) => {
      if (remoteVideo.current && event.streams[0]) {
        remoteVideo.current.srcObject = event.streams[0];
        remoteVideo.current.play().catch(() => {});
      }
    };

    pc.onicecandidate = (event) => {
      if (event.candidate && socketRef?.current) {
        socketRef.current.emit("ice_candidate", {
          to: targetId,
          candidate: event.candidate
        });
      }
    };

    return pc;
  };

  const startCall = async (userIdParam) => {
    try {

      const partnerId = userIdParam || getPartnerId();
      if (!partnerId) return console.warn("No target to call");

      // stop previous stream if exists
      if (localStreamRef.current) {
        localStreamRef.current.getTracks().forEach(t => t.stop());
      }

      const stream = await navigator.mediaDevices.getUserMedia({
        video: true,
        audio: true
      });

      localStreamRef.current = stream;

      if (localVideo.current) {
        localVideo.current.srcObject = stream;
        localVideo.current.play().catch(() => {});
      }

      const pc = createPeer(partnerId);

      // add tracks
      stream.getTracks().forEach(track => {
        pc.addTrack(track, stream);
      });

      const offer = await pc.createOffer();
      await pc.setLocalDescription(offer);

      socketRef.current.emit("call_user", {
        to: partnerId,
        offer,
        from: getMe()?._id
      });

      peerRef.current = pc;
      setCallActive(true);

    } catch (err) {
      console.error("startCall error", err);
    }
  };

  const acceptCall = async () => {
    try {

      if (!incomingCall) return;

      const partnerId = incomingCall.from;

      if (localStreamRef.current) {
        localStreamRef.current.getTracks().forEach(t => t.stop());
      }

      const stream = await navigator.mediaDevices.getUserMedia({
        video: true,
        audio: true
      });

      localStreamRef.current = stream;

      if (localVideo.current) {
        localVideo.current.srcObject = stream;
        localVideo.current.play().catch(() => {});
      }

      const pc = createPeer(partnerId);

      // IMPORTANT: set remote description first
      await pc.setRemoteDescription(incomingCall.offer);

      // add tracks
      stream.getTracks().forEach(track => {
        pc.addTrack(track, stream);
      });

      const answer = await pc.createAnswer();
      await pc.setLocalDescription(answer);

      socketRef.current.emit("answer_call", {
        to: partnerId,
        answer
      });

      peerRef.current = pc;

      setIncomingCall(null);
      setCallActive(true);

    } catch (err) {
      console.error("acceptCall error", err);
    }
  };

  const endCall = () => {
    // close peer connection
    try {
      if (peerRef.current) {
        try { peerRef.current.close(); } catch (e) {}
        peerRef.current = null;
      }
      // stop local tracks
      if (localStreamRef.current) {
        localStreamRef.current.getTracks().forEach(t => t.stop());
        localStreamRef.current = null;
      }
      if (localVideo.current) localVideo.current.srcObject = null;
      if (remoteVideo.current) remoteVideo.current.srcObject = null;
    } finally {
      setCallActive(false);
      setIncomingCall(null);
    }
  };

  // --- messaging functions ---
  const send = async () => {
    if (!input.trim() || !chat) return;
    try {
      const res = await API.post('/messages', { content: input, chat: chat._id });
      setInput('');
      setMessages((prev) => [...prev, res.data]);
      const socket = socketRef?.current;
      if (socket) socket.emit('new_message', res.data);
      scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
    } catch (err) { console.error(err); }
  };

  const handleTyping = () => {
    const socket = socketRef?.current;
    if (!socket || !chat) return;
    socket.emit('typing', chat._id);

    if (typingTimeout.current) clearTimeout(typingTimeout.current);
    typingTimeout.current = setTimeout(() => {
      socket.emit('stop_typing', chat._id);
    }, 1000);
  };

  // --- file upload handlers (unchanged) ---
  const handleFileUpload = async (e) => {
    const file = e.target.files[0];
    if (!file || !chat) return;
    try {
      const formData = new FormData();
      formData.append('file', file);
      const uploadRes = await API.post('/upload/image', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      const fileUrl = uploadRes.data.url;
      const res = await API.post('/messages', {
        chat: chat._id,
        image: file.type.startsWith('image') ? fileUrl : null,
        file: !file.type.startsWith('image') ? fileUrl : null
      });
      const message = res.data;
      setMessages(prev => [...prev, message]);
      const socket = socketRef.current;
      if (socket) socket.emit('new_message', message);
      scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
    } catch (err) {
      console.error('File upload failed:', err);
    }
  };

  const handleFileSelect = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setSelectedFile(file);
    if (file.type.startsWith('image') || file.type.startsWith('video')) {
      setPreview(URL.createObjectURL(file));
    } else {
      setPreview(null);
    }
  };

  const sendFile = async () => {
    if (!selectedFile || !chat) return;
    try {
      setFileLoading(true);
      const formData = new FormData();
      formData.append('file', selectedFile);
      const uploadRes = await API.post('/upload/image', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      const fileUrl = uploadRes.data.url;
      const res = await API.post('/messages', {
        chat: chat._id,
        image: selectedFile.type.startsWith('image') ? fileUrl : null,
        file: !selectedFile.type.startsWith('image') ? fileUrl : null
      });
      setMessages(prev => [...prev, res.data]);
      socketRef.current?.emit('new_message', res.data);
      setSelectedFile(null);
      setPreview(null);
    } catch (err) {
      console.error(err);
    } finally {
      setFileLoading(false);
    }
  };

  const cancelFile = () => {
    setSelectedFile(null);
    setPreview(null);
  };

  // cleanup on unmount
  useEffect(() => {
    return () => {
      endCall();
    };
  }, []);

  // simple UI to invoke call: tries to get partner id from chat
  const partnerId = getPartnerId();

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', flex: 1 }}>

      {/* MESSAGE AREA */}
      <div style={{ flex: 1, overflowY: 'auto', padding: 12, background: '#f5f5f5' }}>
        {messages.map((m) => (<MessageBubble key={m._id || Math.random()} m={m} />))}
        <div ref={scrollRef} />
      </div>

      {/* TYPING */}
      {isTyping && <TypingIndicator />}

      {/* CALL UI: buttons, incoming prompt, and video windows */}
      <div style={{ padding: 8, display: 'flex', gap: 8, alignItems: 'center', justifyContent: 'flex-end' }}>
        {!callActive && <button onClick={() => startCall(partnerId)} disabled={!partnerId}>📹 Video Call</button>}
        {!callActive && <button onClick={() => startCall(partnerId)} disabled={!partnerId}>🎧 Audio Call</button>}
        {callActive && <button onClick={endCall}>End Call</button>}
      </div>

      {incomingCall && (
        <div style={{ padding: 10, background: '#fff1', border: '1px solid #ddd', margin: 8 }}>
          Incoming call...
          <div style={{ marginTop: 8 }}>
            <button onClick={acceptCall}>Accept</button>
            <button onClick={() => setIncomingCall(null)} style={{ marginLeft: 8 }}>Decline</button>
          </div>
        </div>
      )}

      {callActive && (
        <div style={{ display: 'flex', gap: 8, padding: 8 }}>
          <video
  ref={localVideo}
  autoPlay
  muted
  playsInline
  style={{ width: 160, height: 120, background: "#000" }}
/>

<video
  ref={remoteVideo}
  autoPlay
  playsInline
  style={{ width: 320, height: 240, background: "#000" }}
/>
        </div>
      )}

      {/* FILE PREVIEW */}
      {selectedFile && (
        <div style={{ padding: 10, borderTop: '1px solid #ddd', background: '#fafafa', position: 'relative' }}>
          <button onClick={cancelFile} style={{ position: 'absolute', top: 5, right: 5, border: 'none', background: 'transparent', fontSize: 16, cursor: 'pointer' }}>✖</button>
          {preview && selectedFile.type.startsWith('image') && <img src={preview} alt="preview" style={{ maxWidth: 200, borderRadius: 6 }} />}
          {preview && selectedFile.type.startsWith('video') && <video src={preview} controls style={{ maxWidth: 250 }} />}
          {!preview && <div>📎 {selectedFile.name}</div>}
          <button onClick={sendFile} disabled={fileLoading} style={{ marginTop: 8, padding: '6px 12px', background: fileLoading ? '#999' : '#0084ff', color: '#fff', border: 'none', borderRadius: 6, cursor: fileLoading ? 'not-allowed' : 'pointer' }}>
            {fileLoading ? 'Sending...' : 'Send File'}
          </button>
        </div>
      )}

      {/* INPUT BAR */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 10, padding: 10, borderTop: '1px solid #ddd', background: '#fff' }}>
        <input type="file" onChange={handleFileSelect} style={{ width: 120 }} />
        <input value={input} onChange={(e) => { setInput(e.target.value); handleTyping(); }} placeholder="Type a message..." style={{ flex: 1, padding: 10, borderRadius: 6, border: '1px solid #ccc', fontSize: 14 }} />
        <button onClick={send} style={{ padding: '10px 16px', background: '#0084ff', color: 'white', border: 'none', borderRadius: 6, cursor: 'pointer' }}>Send</button>
      </div>

    </div>
  );
}
